import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export type BJPhase = 'WAITING' | 'BETTING' | 'DEALING' | 'PLAYING' | 'PAYOUT';

export interface BJPlayerDTO {
userId: number;
name: string;
seat: number;
bet: number;
hand: string[];
total: number;
turn: boolean;
bust: boolean;
stand: boolean;
blackjack: boolean;
delta?: number | null;
}

export interface BlackjackStateDTO {
tableId: number;
phase: BJPhase;
minBet: number;
maxBet: number;
dealerCards: string[];
dealerReveal: boolean;
dealerTotal: number;
players: BJPlayerDTO[];
endsInMs: number;
myUserId: number;
}

export class BlackjackStateParser implements IMessageParser {
private _data: BlackjackStateDTO | null = null;

public flush(): boolean {
this._data = null;
return true;
}

public parse(wrapper: IMessageDataWrapper): boolean {
if (!wrapper) return false;

try {
const tableId = wrapper.readInt();
const phaseRaw = wrapper.readString();
const phase = (['WAITING','BETTING','DEALING','PLAYING','PAYOUT'] as const)
.includes(phaseRaw as BJPhase) ? (phaseRaw as BJPhase) : 'WAITING';

const minBet = wrapper.readInt();
const maxBet = wrapper.readInt();

const dealerCount = wrapper.readInt();
const dealerCards: string[] = [];
for (let i = 0; i < dealerCount; i++) dealerCards.push(wrapper.readString());

const dealerReveal = wrapper.readBoolean();
const dealerTotal = wrapper.readInt();

const playersCount = wrapper.readInt();
const players: BJPlayerDTO[] = [];

for (let i = 0; i < playersCount; i++) {
const userId = wrapper.readInt();
const name = wrapper.readString();
const seat = wrapper.readInt();
const bet = wrapper.readInt();

const handLen = wrapper.readInt();
const hand: string[] = [];
for (let h = 0; h < handLen; h++) hand.push(wrapper.readString());

const total = wrapper.readInt();
const turn = wrapper.readBoolean();
const bust = wrapper.readBoolean();
const stand = wrapper.readBoolean();
const blackjack = wrapper.readBoolean();

const hasDelta = wrapper.readBoolean();
const delta = hasDelta ? wrapper.readInt() : null;

players.push({ userId, name, seat, bet, hand, total, turn, bust, stand, blackjack, delta });
}

const endsInMs = wrapper.readInt();

// FINAL: myUserId
let myUserId = 0;
try {
myUserId = wrapper.readInt();
if (Number.isNaN(myUserId)) myUserId = 0;
} catch (e) {
console.warn('[BJ:Parser] Packet had no trailing myUserId; defaulting to 0');
myUserId = 0;
}

this._data = {
tableId, phase, minBet, maxBet,
dealerCards, dealerReveal, dealerTotal,
players, endsInMs, myUserId
};

// Drift check if available
const avail = (wrapper as any).bytesAvailable ?? 0;
if (avail > 0) {
console.warn(`[BJ:Parser] WARNING: ${avail} unread bytes after parse (field order mismatch?)`);
}

// Debug snapshot
console.debug(
`[BJ:Parser] table=${tableId} phase=${phase} limits=${minBet}-${maxBet}` +
` dealer=(${dealerCards.join(',')}) reveal=${dealerReveal} dTotal=${dealerTotal}` +
` players=${players.length} endsInMs=${endsInMs} myUserId=${myUserId}`
);

return true;
} catch (err) {
console.error('[BJ:Parser] failed:', err);
this._data = null;
return false;
}
}

public get data(): BlackjackStateDTO | null {
return this._data;
}
}
